import shlex

def executeCommand():
    command = input("Enter command: ").strip()
    if not command:
        print("Empty command")
        return
    parts = shlex.split(command)
    try:
        subprocess.run(parts, check=True)
    except subprocess.CalledProcessError as e:
        print(f"Command failed with error: {e}")

